import React from 'react';
import { useStaticQuery, graphql } from 'gatsby';
import Layout from '../../components/layout';
import SectionMenu from '../../components/sections/menu';
import Thumbnails from '../../components/thumbnails';

const WorksPage = () => {
  const worksThumbnails = useStaticQuery(graphql`
    {
      allFile(filter: { relativeDirectory: { eq: "works-thumbnails" } }) {
        edges {
          node {
            childImageSharp {
              gatsbyImageData(width: 400)
            }
            name
          }
        }
      }
    }
  `);

  const get = (name, link) => {
    const [{ node }] = worksThumbnails.allFile.edges.filter(
      worksThumbnail => worksThumbnail.node.name === name
    );

    return {
      name: node?.name,
      image: node?.childImageSharp?.gatsbyImageData,
      link
    };
  };

  const datas = [
    get('portfolio_top_20', '20'),
    get('portfolio_top_18', '18'),
    get('portfolio_top_01', '01')
  ];

  return (
    <Layout>
      <SectionMenu />
      <Thumbnails datas={datas} />
    </Layout>
  );
};

export default WorksPage;
